299→// Update session progress bar
300→function updateProgressBar() {
301→  const workout = getTodaysWorkout();
302→  const bar = document.getElementById('session-progress-bar');
303→  if (!workout || !bar) {
304→    if (bar) bar.style.width = '0%';
305→    return;
306→  }
307→
308→  const log = loadLog();
309→  const total = workout.exercises.length;
310→  let completed = 0;
311→
312→  workout.exercises.forEach((ex, index) => {
313→    const key = `${currentState.globalDay}_${index}`;
314→    if (log[key] && log[key].completed) {
315→      completed++;
316→    }
317→  });
318→
319→  const percent = total > 0 ? (completed / total) * 100 : 0;
320→  bar.style.width = `${percent}%`;
