329→// Get the last recorded weight for an exercise
330→function getLastWeight(exerciseName) {
331→  const log = loadLog();
332→  let lastWeight = null;
333→  let lastDay = 0;
334→
335→  for (const key in log) {
336→    if (log[key].exercise === exerciseName && log[key].day > lastDay) {
337→      lastWeight = log[key].weight;
338→      lastDay = log[key].day;
339→    }
340→  }
341→
342→  return lastWeight;
343→}
