387→// Decrement weight for an exercise
388→function decrementWeight(exerciseKey, increment = 5) {
389→  const input = document.querySelector(`input[data-key="${exerciseKey}"]`);
390→  if (!input) return;
391→
392→  let currentValue = parseFloat(input.value) || parseFloat(input.placeholder) || 10;
393→  const newValue = Math.max(currentValue - increment, 5); // Min 5lbs
394→  input.value = newValue;
